// Six prompts — one per task type the router recognises.
// Dry-run mode means NO API calls are made; we just see which model wins.
return [
  {
    json: {
      label: '1 · Coding',
      prompt: 'Write a TypeScript function that debounces async calls and returns a promise that resolves with the latest result.'
    }
  },
  {
    json: {
      label: '2 · Analysis',
      prompt: 'Analyze the trade-offs between microservices and a monolithic architecture for a startup with 3 engineers.'
    }
  },
  {
    json: {
      label: '3 · Writing',
      prompt: 'Write a professional email to a client explaining a two-week delay in the project delivery.'
    }
  },
  {
    json: {
      label: '4 · Summarization',
      prompt: 'Summarize the key points of the following article in 5 bullet points: [paste article here]'
    }
  },
  {
    json: {
      label: '5 · Classification',
      prompt: 'Classify this customer review as positive, negative, or neutral: "The product arrived on time but the packaging was damaged."'
    }
  },
  {
    json: {
      label: '6 · Chat',
      prompt: 'Hey, how are you today?'
    }
  }
];

// Pretty-print the routing decision for each prompt.
const item = $input.item.json;
return [{
  json: {
    label:       item.label,
    prompt:      item.prompt.slice(0, 60) + '…',
    task:        item.detectedTask,
    confidence:  item.detectedTaskConfidence,
    winner:      item.selectedModel,
    provider:    item.selectedProvider,
    score:       item.selectedScore,
    top3: (item.scoreBreakdown || []).map(m =>
      `${m.model} (${m.score}) tf=${m.breakdown.taskFit} cost=${m.breakdown.cost}`
    )
  }
}];

// Merge the three mode results side-by-side for comparison.
const quality = $('AI Router · Quality').first().json;
const cost    = $('AI Router · Cost').first().json;
const speed   = $('AI Router · Speed').first().json;

return [{
  json: {
    prompt: quality.prompt,
    quality: {
      model:          quality.modelUsed,
      provider:       quality.providerUsed,
      estimatedCost:  quality.estimatedCostUSD,
      responseLength: quality.response?.length
    },
    cost: {
      model:          cost.modelUsed,
      provider:       cost.providerUsed,
      estimatedCost:  cost.estimatedCostUSD,
      responseLength: cost.response?.length
    },
    speed: {
      model:          speed.modelUsed,
      provider:       speed.providerUsed,
      estimatedCost:  speed.estimatedCostUSD,
      responseLength: speed.response?.length
    }
  }
}];
